import math

from .base import Shape, _validate_positive_number


class Circle(Shape):
    def __init__(self, radius: float) -> None:
        self._radius = _validate_positive_number(radius, "radius")

    @property
    def radius(self) -> float:
        return self._radius

    def area(self) -> float:
        return math.pi * self._radius * self._radius


class Rectangle(Shape):
    def __init__(self, width: float, height: float) -> None:
        self._width = _validate_positive_number(width, "width")
        self._height = _validate_positive_number(height, "height")

    @property
    def width(self) -> float:
        return self._width

    @property
    def height(self) -> float:
        return self._height

    def area(self) -> float:
        return self._width * self._height


