from .base import _validate_positive_number
from .shapes import Circle, Rectangle


class Cylinder:
    def __init__(self, base_circle: Circle, height: float) -> None:
        if not isinstance(base_circle, Circle):
            raise TypeError("base_circle must be an instance of Circle")
        self._base_circle = base_circle
        self._height = _validate_positive_number(height, "height")

    @property
    def base_circle(self) -> Circle:
        return self._base_circle

    @property
    def height(self) -> float:
        return self._height

    def volume(self) -> float:
        return self._base_circle.area() * self._height


class Cuboid:
    def __init__(self, base_rectangle: Rectangle, depth: float) -> None:
        if not isinstance(base_rectangle, Rectangle):
            raise TypeError("base_rectangle must be an instance of Rectangle")
        self._base_rectangle = base_rectangle
        self._depth = _validate_positive_number(depth, "depth")

    @property
    def base_rectangle(self) -> Rectangle:
        return self._base_rectangle

    @property
    def depth(self) -> float:
        return self._depth

    def volume(self) -> float:
        return self._base_rectangle.area() * self._depth
